  "summary": "围绕断连的 Trim Cooler Outlet 流股以及参数设置异常的 Recycle Pump 生成候选修复提案。",
  "answers": [
    {
      "role": "assistant",
      "content": "根据当前流程图的状态和诊断信息，已生成以下修改建议：1. 为冷却器出口提供下游连接占位符以修复拓扑；2. 修正回收泵的效率并标记出口压力目标以待确认，确保其大于入口压力。"
    }
  ],
  "issues": [
    {
      "code": "STREAM_DISCONNECTED",
      "severity": "error",
      "description": "Trim Cooler Outlet 未连接到任何下游节点，导致求解拓扑无效。",
      "citations": [
        "diag-1",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    },
    {
      "code": "PUMP_OUTLET_PRESSURE_TARGET_INVALID",
      "severity": "error",
      "description": "Recycle Pump 的出口压力目标设定为 150 kPa，低于入口流股压力 190 kPa。",
      "citations": [
        "diag-2",
        "flowdoc-unit-1"
      ]
    },
    {
      "code": "UNIT_PARAMETER_OUT_OF_RANGE",
      "severity": "warning",
      "description": "Recycle Pump 效率设置为 108%，超出物理合理范围。",
      "citations": [
        "diag-3",
        "flowdoc-unit-1"
      ]
    }
  ],
  "proposed_actions": [
    {
      "action": "candidate_edit",
      "title": "补全 Trim Cooler Outlet 拓扑连接",
      "target": "stream:cooler-outlet-81",
      "rationale": "流股因缺乏下游节点导致拓扑无效，需补充连接目标以恢复求解域连通性。",
      "patch": {
        "connection_placeholder": {
          "target_unit_id": "<downstream_consumer_or_export_sink>"
        }
      },
      "risk_level": "high",
      "requires_confirmation": true,
      "citations": [
        "diag-1",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    },
    {
      "action": "candidate_edit",
      "title": "修正 Recycle Pump 压力目标与效率",
      "target": "unit:pump-12",
      "rationale": "将泵效率修正为经验合理范围内的 80%，并标记出口压力占位符等待设定一个高于入口压力的合法值。",
      "patch": {
        "parameter_updates": {
          "efficiency_percent": 80
        },
        "parameter_placeholders": {
          "outlet_pressure_target_kpa": "<must_be_greater_than_190>"
        }
      },
      "risk_level": "medium",
      "requires_confirmation": true,
      "citations": [
        "diag-2",
        "diag-3",
        "flowdoc-unit-1",
